module top_module(rst, rw, X, Y, Z, Rz, Rx, Ry);input rst;
  input rw; 
  input [3:0] X;
  input [3:0] Y;
  input [3:0] Z;
  input [31:0] Rz;
  output [31:0] Rx;
  output [31:0] Ry;

  reg [31:0] unused_gregs [15:0];
  integer i;

  always @ (*) begin
    if (rst) begin
      for(i=0; i<16; i=i+1) begin
        unused_gregs[i] <= i;
      end
    end else begin 
      if(rw == 1)
        unused_gregs[Z] <= Rz;
    end
  end

  assign Rx = unused_gregs[X];
  assign Ry = unused_gregs[Y];endmodule
